import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";

// components
import Navbar from "components/Navbars/AuthNavbar.js";
import Footer from "components/Footers/Footer.js";

export default function Landing() {
  // ✅ النصوص باللغات
  const texts = [
    "Hello",
    "Bonjour",
    "Ciao",
    "Hola",
    "こんにちは",
    "你好",
    "안녕하세요",
    "नमस्ते",
    "مرحبا"
  ];

  // ✅ state
  const [index, setIndex] = useState(0);

  // ✅ تغيير النص كل 2 ثواني
  useEffect(() => {
    const interval = setInterval(() => {
      setIndex((prev) => (prev + 1) % texts.length);
    }, 2000);

    return () => clearInterval(interval);
  }, []);

  return (
    <>
      <Navbar transparent />
      <main>
        <div className="relative pt-16 pb-32 flex content-center items-center justify-center min-h-screen">
          <div
            className="absolute top-0 w-full h-full bg-center bg-cover"
            style={{
              backgroundImage:
                "url('https://t4.ftcdn.net/jpg/09/09/79/85/360_F_909798513_DhTQUUB8Sexbj5rBgsz5qwkarSwvQ3mA.jpg')",
            }}
          >
            {/* ❌ حذفنا الطبقة السوداء باش الصورة تكون واضحة */}
          </div>

          <div className="container relative mx-auto">
            <div className="items-center flex flex-wrap">
              <div className="w-full lg:w-6/12 px-4 ml-auto mr-auto text-center">
                <div className="pr-12">

                  {/* ✅ هنا النص المتغيّر */}
                  <h1
                    key={texts[index]}
                    className="text-white font-semibold text-5xl transition-all duration-500"
                  >
                    {texts[index]}
                  </h1>

                  <p className="mt-4 text-lg text-blueGray-200">
                    Welcome to our website
                  </p>

                </div>
              </div>
            </div>
          </div>
        </div>

        {/* باقي الكود كما هو */}
      </main>
      <Footer />
    </>
  );
}
